from collections import defaultdict


def parse_query_string(qs: str) -> dict[str, list[str]]:
    """
    Parses a URL query string into a dictionary mapping each key to a list of its values.

    Args:
        qs: The query string to be parsed (e.g., 'a=1&b=2&a=3').

    Returns:
        A dictionary where keys are strings and values are lists of strings.
        A parameter without an '=' maps to a list containing a single empty string.
        An empty input string returns an empty dictionary.

    Raises:
        TypeError: If the input `qs` is not a string.
    """
    if not isinstance(qs, str):
        raise TypeError(f"Expected str, got {type(qs).__name__}")

    if not qs:
        return {}

    result: dict[str, list[str]] = defaultdict(list)

    for pair in qs.split("&"):
        if not pair:
            continue

        if "=" in pair:
            key, value = pair.split("=", 1)
            result[key].append(value)
        else:
            result[pair].append("")

    return dict(result)
