from collections import defaultdict
from typing import Dict, List


def parse_query_string(qs: str) -> Dict[str, List[str]]:
    """
    Parses a URL query string into a dictionary mapping keys to lists of values.

    Args:
        qs: The query string to parse (e.g., 'a=1&b=2&a=3').

    Returns:
        A dictionary where each key maps to a list of strings representing its values.

    Raises:
        TypeError: If the input qs is not a string.
    """
    if not isinstance(qs, str):
        raise TypeError(f"Expected str, got {type(qs).__name__}")

    if not qs:
        return {}

    result: Dict[str, List[str]] = defaultdict(list)

    for pair in qs.split("&"):
        if not pair:
            continue

        if "=" in pair:
            key, value = pair.split("=", 1)
            result[key].append(value)
        else:
            result[pair].append("")

    return dict(result)
